&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function-name function&#34;&gt;restart&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;stop&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sleep&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;start&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;&lt;span class=&#34;token variable&#34;&gt;$1&lt;/span&gt;&#34;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;start&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;start&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;stop&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;stop&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;restart&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;restart&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;*&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;echo&lt;/span&gt; $&lt;span class=&#34;token string&#34;&gt;&#34;Usage: &lt;span class=&#34;token variable&#34;&gt;$0&lt;/span&gt; &amp;#123;start|stop|restart&amp;#125;&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;exit&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;esac&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;blockquote&gt;
&lt;p&gt;注意：&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;1.1 注： 复制这个脚本到 Linux 可能会丢失最上面的一部分，不知道为什么，通过 xshell 打开 Linux，然后复制这些内容到文件中，会丢失一部分，自己复制过去以后检查清楚是否丢失一些内容。不然就算注册成一个服务也没法用。&lt;/p&gt;
&lt;p&gt;1.2 ROCKETMQ_HOME 的地址、利用 nohup 启动 broker 是指定启动的配置文件都要写对&lt;/p&gt;
&lt;h4 id=&#34;2-将rocketmq服务添加为开机启动服务&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-将rocketmq服务添加为开机启动服务&#34;&gt;#&lt;/a&gt; 2、将 rocketmq 服务添加为开机启动服务&lt;/h4&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;chmod&lt;/span&gt; +x /etc/init.d/rocketmq&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;chkconfig&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;--add&lt;/span&gt; rocketmq&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;blockquote&gt;
&lt;p&gt;再运行 chkconfig --list 查看是否出现以下内容，出现则代表加入成功了&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;注：若出现下图 0-6 都是关，那代表还不能开机自启，再运行  &lt;code&gt;chkconfig rocketmq on&lt;/code&gt; ，然后再运行 chkconfig --list 以后 2-5 都是开以后才行。&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@host-172-20-42-212 rocketmq-5.1.2&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# chkconfig --list&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Note: This output shows SysV services only and does not include native&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      systemd services. SysV configuration data might be overridden by native&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      systemd configuration.&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      If you want to list systemd services use &lt;span class=&#34;token string&#34;&gt;&#39;systemctl list-unit-files&#39;&lt;/span&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      To see services enabled on particular target use&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token string&#34;&gt;&#39;systemctl list-dependencies [target]&#39;&lt;/span&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rocketmq       	&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;:off	&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;:off	&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;:off	&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;:off	&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;:off	&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;:off	&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;:off&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;3-通过service命令来管理rocketmq&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-通过service命令来管理rocketmq&#34;&gt;#&lt;/a&gt; 3、通过 service 命令来管理 rocketmq&lt;/h4&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 启动&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;service&lt;/span&gt; rocketmq start&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 关闭&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;service&lt;/span&gt; rocketmq stop&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 重启&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;service&lt;/span&gt; rocketmq restart&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;-- 启动namesrv&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;nohup&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;sh&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/bin/mqnamesrv &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/logs/mqnamesrv.log &lt;span class=&#34;token operator&#34;&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;2&lt;/span&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;&amp;amp;1&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;-- 验证是否成功&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;tail&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-f&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/logs/mqnamesrv.log&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;-- 启动broker&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;nohup&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;sh&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/bin/mqbroker &lt;span class=&#34;token parameter variable&#34;&gt;-c&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/conf/broker.conf &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;/home/sys_wh/soft/rocketmq-5.1.4/logs/broker.log &lt;span class=&#34;token operator&#34;&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;2&lt;/span&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;&amp;amp;1&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;-- 验证是否成功&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;tail&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-f&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/logs/broker.log&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;--停止broker&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sh&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/bin/mqshutdown broker&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;--停止 namesrv&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sh&lt;/span&gt; /home/sys_wh/soft/rocketmq-5.1.4/bin/mqshutdown namesrv&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;-- 启动管理平台&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;nohup&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;java&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-jar&lt;/span&gt; rocketmq-dashboard-1.0.0.jar   &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; dashboard.log &lt;span class=&#34;token operator&#34;&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;2&lt;/span&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token file-descriptor important&#34;&gt;&amp;amp;1&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;4、设置密码&lt;/p&gt;
&lt;p&gt;4.1 开启 acl 控制&lt;/p&gt;
&lt;p&gt;在 &lt;code&gt;conf/broker.conf&lt;/code&gt;  中开启 &lt;code&gt;aclEnable=true&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;vim&lt;/span&gt; conf/broker.conf&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 最下面增加下面一行&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;aclEnable&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;true&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;4.2 配置账号密码&lt;/p&gt;
&lt;p&gt;修改 &lt;code&gt;conf/plain_acl.yml&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;accounts: 
	# 管理员账号/密码
	accessKey: catsicrocketmq
	secretKey: Catsic1qsx@WDC
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;4.3 配置面板中的密码&lt;/p&gt;
&lt;p&gt;	在 dashboard.jar 包同级目录创建 config 文件夹，将项目底下的 application.properties 上传到 config 文件夹下，将注释放开，设置对应的账号密码。修改后重启&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;rocketmq.config.accessKey=catsicrocketmq
rocketmq.config.secretKey=Catsic1qsx@WDC
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;4.4 当前，已经为 RocketMQ 设置了密码，但是，还存在问题，操作面板没有设置密码，操作面板没有设置密码，在实际应用中，也是很危险的。下面讲解面板设置密码：&lt;/p&gt;
&lt;p&gt;4.5 开启账号密码访问&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# 修改application.properties
# 是否开启账号密码验证
rocketmq.config.loginRequired= true
# 账号密码配置文件为：users.properties，将users.properties上传到config目录，修改内容为
# ,1 为管理员，不加为普通用户
catstiMQ=catsti1qaz@WSX,1
# 修改默认用户配置文件路径
vim application.properties
# 将其修改为：
rocketmq.config.dataPath=./config
# 重启dashboard
&lt;/code&gt;&lt;/pre&gt;

 &lt;h3 id=&#34;常用语法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常用语法&#34;&gt;#&lt;/a&gt; 常用语法&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;#安装软件
pacman -S 包名 ...

#给所有提示设置选项
yes | sudo pacman -S 包名 ...

#只下载包，不安装
pacman -Sw 包名 ...

#清理未安装的包文件，包文件位于 /var/cache/pacman/pkg/ 目录
pacman -Sc

#清理所有的缓存文件
pacman -Scc

#删除单个软件包，保留其全部已经安装的依赖关系
pacman -R 包名

#删除指定软件包，及其所有没有被其他已安装软件包使用的依赖关系
pacman -Rs 包名

#在删除包的同时，删除所有依赖这个软件包的程序
pacman -Rsc 包名

#在删除包时不检查依赖
pacman -Rd 包名

#更新所有包 y更新数据库，yy强制更新，u升级软件
pacman -Syu

#在数据库中查询软件包，查询位置包含了包的名字和描述
pacman -Ss 关键字

#获取已安装软件包所包含文件的列表
pacman -Ql

#从本地安装软件包
pacman -U xxx.tar.gz

#显示软件包依赖树
pactree 包名

# 卸载所有无用包
pacman -c
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;系统配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统配置&#34;&gt;#&lt;/a&gt; 系统配置&lt;/h3&gt;
&lt;h4 id=&#34;设置中国源&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#设置中国源&#34;&gt;#&lt;/a&gt; 设置中国源&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;# 排列中国源
sudo pacman-mirrors -i -c China -m rank
# 选择中科大、阿里、华为等
https://mirrors.ustc.edu.cn/manjaro/
# 同步软件包数据库
sudo pacman -Syy

sudo gedit /etc/pacman.conf
在打开的文件的末尾添加如下内容：
[archlinuxcn]
SigLevel = Optional TrustedOnly
Server = https://mirrors.ustc.edu.cn/archlinuxcn/$arch

修改好上述两个部分后，终端执行下面的指令：
sudo pacman -Syy 
# 安装秘钥
sudo pacman -S archlinuxcn-keyring 
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;时间同步&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时间同步&#34;&gt;#&lt;/a&gt; 时间同步&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;# 安装openNTPD
sudo pacman -S openntpd
# 重启openNTPD
systemctl restart openntpd
# 设置开机启动
systemctl enable openntpd
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;软件安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#软件安装&#34;&gt;#&lt;/a&gt; 软件安装&lt;/h3&gt;
&lt;h4 id=&#34;安装yay&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装yay&#34;&gt;#&lt;/a&gt; 安装 yay&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;# 安装aur工具
sudo pacman -S yay
# 设置中国源
yay --aururl &amp;quot;https://aur.tuna.tsinghua.edu.cn&amp;quot; --save
# 验证是否成功
yay -P -g
# 更新包
yay -Syu
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装base-devel&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装base-devel&#34;&gt;#&lt;/a&gt; 安装 base-devel&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;# 建议提前安装基础包，避免安装其他包时出现依赖错误
sudo pacman -S base-devel
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装vim&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装vim&#34;&gt;#&lt;/a&gt; 安装 vim&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S vim
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装chrom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装chrom&#34;&gt;#&lt;/a&gt; 安装 chrom&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S google-chrome
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装输入法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装输入法&#34;&gt;#&lt;/a&gt; 安装输入法&lt;/h4&gt;
&lt;h5 id=&#34;fcitx搜狗&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#fcitx搜狗&#34;&gt;#&lt;/a&gt; fcitx + 搜狗&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;# 输入法对比：https://wiki.archlinux.org/index.php/Fcitx_(%E7%AE%80%E4%BD%93%E4%B8%AD%E6%96%87)#%E4%B8%AD%E6%96%87
# 安装输入法需要的依赖
yay -S fcitx-im fcitx-configtool fcitx-qt4
# 编辑 ~/.pam_environment（不存在就添加），添加以下内容：
GTK_IM_MODULE=fcitx
QT_IM_MODULE=fcitx
XMODIFIERS=@im=fcitx
# 安装搜狗输入法需要的依赖
yay -S qtwebkit-bin
# 安装搜狗输入法
yay -S fcitx-sogoupinyin 
# 解决搜狗输入法候选项乱码
cd ~/.config
sudo rm -rf SogouPY* sogou*
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;fctix5rime&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#fctix5rime&#34;&gt;#&lt;/a&gt; fctix5+rime&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;先用这个
sudo pacman -S fcitx-rime
sudo pacman -S fcitx-im
sudo pacman -S fcitx-configtool

然后你需要编辑一个文件：
sudo gedit ~/.xprofile

在文件末尾添加如下文本：
export GTK_IM_MODULE=fcitx
export QT_IM_MODULE=fcitx
export XMODIFIERS=&amp;quot;@im=fcitx&amp;quot;
重启一下系统




# 如果上述不可以再使用yay安装，有些包pacman没有
yay -S fcitx5-git fcitx5-config-qt-git fcitx5-gtk-git fcitx5-rime-git
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置&#34;&gt;#&lt;/a&gt; 配置&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;# 编辑 ~/.pam_environment（不存在就添加），添加以下内容：
GTK_IM_MODULE=fcitx5
QT_IM_MODULE=fcitx5
XMODIFIERS=@im=fcitx5
fcitx5 &amp;amp;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;开机自起&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#开机自起&#34;&gt;#&lt;/a&gt; 开机自起&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;sudo cp /usr/share/applications/fcitx5.desktop /etc/xdg/autostart/
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;rime配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rime配置&#34;&gt;#&lt;/a&gt; rime 配置&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;# 如果没有写权限，需要先赋予权限
sudo vim /usr/share/rime-data/build/luna_pinyin.schema.yaml
#配置候选数量
menu:
	page_size: 10
#设置默认为简体
#定位这一行
- name: simplification
	#在下方增加如下配置
	reset: 1
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装deepin移植的微信&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装deepin移植的微信&#34;&gt;#&lt;/a&gt; 安装 deepin 移植的微信&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S deepin-wine-wechat
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装qq-tim&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装qq-tim&#34;&gt;#&lt;/a&gt; 安装 qq &amp;amp;&amp;amp; TIM&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;安装QQ：
sudo pacman -S deepin.com.qq.office
||
sudo pacman -S com.qq.weixin.spark
安装Tim：
sudo pacman -S deepin.com.qq.im
||
sudo pacman -S com.qq.tim.spark
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装typora&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装typora&#34;&gt;#&lt;/a&gt; 安装 typora&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S typora
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;百度网盘&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#百度网盘&#34;&gt;#&lt;/a&gt; 百度网盘&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S baidunetdisk-bin
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装深度截图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装深度截图&#34;&gt;#&lt;/a&gt; 安装深度截图&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;#安装
sudo pacman -S deepin-screenshot
#设置快捷键
系统设置---&amp;gt;工作区---&amp;gt;快捷键---&amp;gt;自定义快捷键---&amp;gt;编辑---&amp;gt;新建---&amp;gt;全局快捷键---&amp;gt;命令URL---&amp;gt;命名/触发器(快捷键)/动作(deepin-screenshot)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装idea&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装idea&#34;&gt;#&lt;/a&gt; 安装 idea&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;下载idea
wget https://download.jetbrains.8686c.com/idea/ideaIC-2020.1.3.tar.gz
解压
tar -zxvf ideaIC-2020.1.3.tar.gz
安装
bin/idea.sh
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装网易云音乐&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装网易云音乐&#34;&gt;#&lt;/a&gt; 安装网易云音乐&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S netease-cloud-music
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装vscode&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装vscode&#34;&gt;#&lt;/a&gt; 安装 vscode&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S visual-studio-code-bin
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装git&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装git&#34;&gt;#&lt;/a&gt; 安装 git&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;yay -S git
yay -S gitkraken
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;安装nodejs&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装nodejs&#34;&gt;#&lt;/a&gt; 安装 NodeJS&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;# 安装nodejs
sudo pacman -S nodejs
# 安装npm
sudo pacman -S npm
# 安装cnpm源
sudo npm install -g cnpm --registry=https://registry.npm.taobao.org 
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;安装wps&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装wps&#34;&gt;#&lt;/a&gt; 安装 wps&lt;/h4&gt;
&lt;h5 id=&#34;自动安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自动安装&#34;&gt;#&lt;/a&gt; 自动安装&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;#如果以下方式不行  使用yay试试
sudo pacman -S wps-office ttf-wps-fonts
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;手动安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#手动安装&#34;&gt;#&lt;/a&gt; 手动安装&lt;/h5&gt;
&lt;pre&gt;&lt;code&gt;# 去官网下载安装deb包
https://linux.wps.cn/
# 安装debtap
yay -S debtap
#安装字体依赖
sudo pacman -S ttf-wps-fonts c
# 更新debtap  
sudo debtap -u
# 静默模式转换安装包  根据提示输入包名随便写   license写GPL
debtap -q xxx.deb
# 安装 如果提示缺少依赖  先安装依赖  再手动安装包
sudo pacman -U xxx.tar.zst
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;系统美化&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统美化&#34;&gt;#&lt;/a&gt; 系统美化&lt;/h3&gt;
&lt;h4 id=&#34;安装latte-dock&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装latte-dock&#34;&gt;#&lt;/a&gt; 安装 latte-dock&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;yay -S latte-dock&lt;/code&gt;  &amp;lt;/br&amp;gt;&lt;br /&gt;
 添加一个新空面板，默认会出现在上面，然后删除下面这个面板&lt;br /&gt;
在新面板上添加必要的部件：应用程序面板，数字时钟，托盘图标&lt;br /&gt;
还可以加全局菜单，显示面板等等 &amp;lt;/br&amp;gt;&lt;br /&gt;
 启动 &lt;code&gt;latte-dock&lt;/code&gt; ，下方就会出现一个 dock 栏，具体配置看自己爱好&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;配置ohmyzsh-插件地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置ohmyzsh-插件地址&#34;&gt;#&lt;/a&gt; 配置 ohmyzsh &lt;a href=&#34;https://github.com/zsh-users&#34;&gt;插件地址&lt;/a&gt;&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;1、首先修改默认 shell 为 zsh:&amp;lt;/br&amp;gt;&lt;br /&gt;
 &lt;code&gt;chsh -s /usr/bin/zsh&lt;/code&gt;  &amp;lt;/br&amp;gt;&lt;br /&gt;
 安装 ohmyzsh &amp;lt;/br&amp;gt;&lt;br /&gt;
wget &lt;a href=&#34;https://github.com/robbyrussell/oh-my-zsh/raw/master/tools/install.sh&#34;&gt;https://github.com/robbyrussell/oh-my-zsh/raw/master/tools/install.sh&lt;/a&gt; -O - | sh &amp;lt;/br&amp;gt;&lt;br /&gt;
 如果每次执行都失败提示被拒绝连接就先改一下 hosts 文件 &amp;lt;/br&amp;gt;&lt;br /&gt;
 &lt;code&gt; sudo nano /etc/hosts&lt;/code&gt;  &amp;lt;/br&amp;gt;&lt;br /&gt;
 把这段话复制到下面 &amp;lt;/br&amp;gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# GitHub Start
151.101.64.133 raw.githubusercontent.com
# GitHub End 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;2、安装 zsh-syntax-highlighting：提供命令高亮&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;git clone https://github.com/zsh-users/zsh-syntax-highlighting.git $&amp;#123;ZSH_CUSTOM:-~/.oh-my-zsh/custom&amp;#125;/plugins/zsh-syntax-highlighting
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;3、安装 autosuggestions：记住你之前使用过的命令&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;git clone git://github.com/zsh-users/zsh-autosuggestions ~/.oh-my-zsh/custom/plugins/zsh-autosuggestions
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;4、安装 incr：（需要注意的是这个插件会拖慢 zsh 的速度，新手入门可以试试）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;git clone git://github.com/makeitjoe/incr.zsh $ZSH_CUSTOM/plugins/incr
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;5、启用所有插件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;nano ~/.zshrc
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;将 plugins=(git) 改为:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;plugins=(git zsh-syntax-highlighting zsh-autosuggestions incr sudo extract)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;6、重载配置&lt;br /&gt;
 &lt;code&gt; source ~/.zshrc&lt;/code&gt; &lt;br /&gt;
 如果想要卸载 oh my zsh，直接执行下面命令 &amp;lt;/br&amp;gt;&lt;br /&gt;
 &lt;code&gt; uninstall oh my zsh&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;优化grub主题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#优化grub主题&#34;&gt;#&lt;/a&gt; 优化 grub 主题&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;准备好主题文档夹，可以在&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuZ25vbWUtbG9vay5vcmcvYnJvd3NlL2NhdC8xMDkvb3JkL2xhdGVzdC8=&#34;&gt; Grub Themes&lt;/span&gt; 挑选下载 &amp;lt;/br&amp;gt;&lt;br /&gt;
1、将主题文档夹移至 /boot/grub/themes/ 下 &amp;lt;/br&amp;gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$ sudo mv -r YourTheme /boot/grub/themes
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;2、更改 Grub 配置文档 &amp;lt;/br&amp;gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;注释掉 GRUB_BACKGROUND 行&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;#GRUB_BACKGROUND=&amp;quot;/usr/share/grub/YourImg.*&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;更改 GRUB_THEME 行&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;GRUB_THEME=&amp;quot;/usr/share/grub/themes/YourTheme/theme.txt&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;更新 Grub 配置&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;$ sudo update-grub
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;重启即可看见效果啦～&amp;lt;/br&amp;gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;mark&gt;3、注：在 Grub Themes 下载的主题压缩包，&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1pbnN0YWxsLTR0M2s2bWo0emxzYjQyNmRxZTdhYm9hMjUyM2Ftd3phdzUyYS5zaA==&#34;&gt;其中一部分有安装脚本 install.sh&lt;/span&gt;，解压后，进入主题文档夹，执行 sudo ./install.sh 即可配置成功，等效于上述的步骤。&lt;/mark&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;参考文档&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参考文档&#34;&gt;#&lt;/a&gt; 参考文档&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMTdLNHkxSzd1cg==&#34;&gt;发行版的安装&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMUd2NDExNzdHRQ==&#34;&gt;软件包管理和中文化配置&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMUFRNHkxWjd3ag==&#34;&gt;自启动程序配置&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMVh2NDExTDc1cQ==&#34;&gt;桌面环境的切换&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC8xMTQyOTYxMjk=&#34;&gt;环境配置&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuZGF6aHVhbmxhbi5jb20vMjAxOS8wOC8yNy81ZDY1NGM5MGIwYjgzLw==&#34;&gt;grub 主题修改&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Manjaro &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aGFuZ19oYW9feXUxMjMuZ2l0ZWUuaW8vMjAyMS8wMS8xNC9tYW5qYXJvLWFuLXpodWFuZy1oZS1wZWktemhpLw==&#34;&gt;命令安装&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1 id=&#34;linux-安装openjdk&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#linux-安装openjdk&#34;&gt;#&lt;/a&gt; 【Linux】 安装 OpenJDK&lt;/h1&gt;
&lt;h2 id=&#34;在线安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在线安装&#34;&gt;#&lt;/a&gt; 在线安装&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;### a) 检查系统中是否有java环境
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​                     &lt;code&gt;rpm -qa | grep java&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;### b) 使用yum安装/升级OpenJDK：
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;​                     &lt;code&gt;yum -y install java-1.8.0-openjdk-devel&lt;/code&gt; &lt;br /&gt;
​    ### c) 查找 OpenJDK 安装路径：&lt;br /&gt;
​                     &lt;code&gt;[root@node01 ~]# which java       //找到java的执行路径&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;/usr/bin/java&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# ls -lrt /usr/bin/java       // 执行路径指向环境的软连接&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;lrwxrwxrwx &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt; root root &lt;span class=&#34;token number&#34;&gt;22&lt;/span&gt; Sep &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;21&lt;/span&gt;:23 /usr/bin/java -&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; /etc/alternatives/java&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# ls -lrt /etc/alternatives/java     // 最终指向安装路径&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;lrwxrwxrwx &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt; root root &lt;span class=&#34;token number&#34;&gt;73&lt;/span&gt; Sep &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;21&lt;/span&gt;:23 /etc/alternatives/java -&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; /usr/lib/jvm/java-1.8.0-openjdk-1.8.0.302.b08-0.el7_9.x86_64/jre/bin/java&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;d-配置环境变量规范配置方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#d-配置环境变量规范配置方法&#34;&gt;#&lt;/a&gt; d) 配置环境变量（规范配置方法）：&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 java&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# vi /etc/profile.d/my_env.sh&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 添加如下环境变量：&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#JAVA_HOME&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;token assign-left variable&#34;&gt;JAVA_HOME&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;/usr/lib/jvm/jre-1.8.0-openjdk-1.8.0.322.b06-1.el7_9.x86_64&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;token assign-left variable&#34;&gt;&lt;span class=&#34;token environment constant&#34;&gt;PATH&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token environment constant&#34;&gt;$PATH&lt;/span&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$JAVA_HOME&lt;/span&gt;/bin&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;e-保存退出后刷新配置或重启xshell窗口&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#e-保存退出后刷新配置或重启xshell窗口&#34;&gt;#&lt;/a&gt; e) 保存退出后刷新配置（或重启 Xshell 窗口）：&lt;/h3&gt;
&lt;p&gt;[root@node01 java]# source /etc/profile.d/my_env.sh&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-BASH&#34;&gt;[root@node01 ~]# java -version

openjdk version &amp;quot;1.8.0_302&amp;quot;

OpenJDK Runtime Environment (build 1.8.0_302-b08)

OpenJDK 64-Bit Server VM (build 25.302-b08, mixed mode)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;离线安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#离线安装&#34;&gt;#&lt;/a&gt; 离线安装&lt;/h2&gt;
&lt;h3 id=&#34;a-若集群无外网则可以使用openjdk二进制包进行离线部署-预先下载openjdk-180_41-b04&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#a-若集群无外网则可以使用openjdk二进制包进行离线部署-预先下载openjdk-180_41-b04&#34;&gt;#&lt;/a&gt; a) 若集群无外网，则可以使用 OpenJDK 二进制包进行离线部署。预先下载 OpenJDK 1.8.0_41-b04：&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb3dubG9hZC5qYXZhLm5ldC9vcGVuamRrL2pkazh1NDEvcmkvb3Blbmpkay04dTQxLWIwNC1saW51eC14NjQtMTRfamFuXzIwMjAudGFyLmd6&#34;&gt;下载地址&lt;/span&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;b-检查当前系统中是否已有java运行环境jre若有执行卸载&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#b-检查当前系统中是否已有java运行环境jre若有执行卸载&#34;&gt;#&lt;/a&gt; b) 检查当前系统中是否已有 Java 运行环境（JRE），若有，执行卸载：&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# rpm -qa | grep java&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;c-卸载自带jre命令如无跳过&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#c-卸载自带jre命令如无跳过&#34;&gt;#&lt;/a&gt; c) 卸载自带 JRE 命令 (如无跳过)：&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# yum -y remove java*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# yum -y remove tzdata-java*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;d-将openjdk-8u41-b04-linux-x64-14_jan_2020targz上传至optsoftware目录下&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#d-将openjdk-8u41-b04-linux-x64-14_jan_2020targz上传至optsoftware目录下&#34;&gt;#&lt;/a&gt; d) 将 openjdk-8u41-b04-linux-x64-14_jan_2020.tar.gz 上传至 /opt/software 目录下：&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# mkdir /opt/software&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;e-解压-将解压后的目录转移至usrjava下&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#e-解压-将解压后的目录转移至usrjava下&#34;&gt;#&lt;/a&gt; e) 解压、将解压后的目录转移至 /usr/java/ 下：&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;                #### 解压
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-BASH&#34;&gt;[root@node01 software]# tar xf openjdk-8u41-b04-linux-x64-14_jan_2020.tar.gz
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;                #### 将解压后的目录转移至/usr/java/下：
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 software&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# mv /opt/software/java-se-8u41-ri /usr/java&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 software&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# cd /usr/java&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 java&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# ll&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;total &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;drwxr-xr-x &lt;span class=&#34;token number&#34;&gt;9&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;143&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;219&lt;/span&gt; Jan &lt;span class=&#34;token number&#34;&gt;15&lt;/span&gt;  &lt;span class=&#34;token number&#34;&gt;2020&lt;/span&gt; java-se-8u41-ri&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;f-配置环境变量规范配置方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#f-配置环境变量规范配置方法&#34;&gt;#&lt;/a&gt; f) 配置环境变量（规范配置方法）：&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 java&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# vi /etc/profile.d/my_env.sh&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;g-添加如下环境变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#g-添加如下环境变量&#34;&gt;#&lt;/a&gt; g) 添加如下环境变量：&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;#JAVA_HOME
export JAVA_HOME=/usr/java/java-se-8u41-ri
export PATH=$PATH:$JAVA_HOME/bin
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;h-保存退出后刷新配置或重启xshell窗口&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#h-保存退出后刷新配置或重启xshell窗口&#34;&gt;#&lt;/a&gt; h) 保存退出后刷新配置（或重启 Xshell 窗口）：&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 java&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# source /etc/profile.d/my_env.sh&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# java -version&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;openjdk version &lt;span class=&#34;token string&#34;&gt;&#34;1.8.0_41&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;OpenJDK Runtime Environment &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;build &lt;span class=&#34;token number&#34;&gt;1.8&lt;/span&gt;.0_41-b04&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;OpenJDK &lt;span class=&#34;token number&#34;&gt;64&lt;/span&gt;-Bit Server VM &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;build &lt;span class=&#34;token number&#34;&gt;25.40&lt;/span&gt;-b25, mixed mode&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;命令历史&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#命令历史&#34;&gt;#&lt;/a&gt; 命令历史&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;以：和 / 开头的命令都有历史纪录，可以首先键入：或 / 然后按上下箭头来选择某个历史命令。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;启动vim&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#启动vim&#34;&gt;#&lt;/a&gt; 启动 vim&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;在命令行窗口中输入以下命令即可&lt;/p&gt;
&lt;p&gt;vim 直接启动 vim&lt;/p&gt;
&lt;p&gt;vim filename 打开 vim 并创建名为 filename 的文件&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;文件命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文件命令&#34;&gt;#&lt;/a&gt; 文件命令&lt;/h2&gt;
&lt;blockquote&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 打开单个文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;vim&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;file&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 同时打开多个文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;vim&lt;/span&gt; file1 file2 file3 &lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt;.&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 在 vim 窗口中打开一个新文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:open &lt;span class=&#34;token function&#34;&gt;file&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 在新窗口中打开文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:split &lt;span class=&#34;token function&#34;&gt;file&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 切换到下一个文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:bn&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 切换到上一个文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:bp&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 查看当前打开的文件列表，当前正在编辑的文件会用 [] 括起来。&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:args&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 打开远程文件，比如 ftp 或者 share folder&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:e ftp://192.168.10.76/abc.txt&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;:e &lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;qadrive&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;test&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;.txt&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/blockquote&gt;
&lt;h1 id=&#34;vim的模式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vim的模式&#34;&gt;#&lt;/a&gt; vim 的模式&lt;/h1&gt;
&lt;h2 id=&#34;导航命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#导航命令&#34;&gt;#&lt;/a&gt; 导航命令&lt;/h2&gt;
&lt;p&gt;% 括号匹配&lt;/p&gt;
&lt;h2 id=&#34;插入命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#插入命令&#34;&gt;#&lt;/a&gt; 插入命令&lt;/h2&gt;
&lt;p&gt;i 在当前位置生前插入&lt;/p&gt;
&lt;p&gt;I 在当前行首插入&lt;/p&gt;
&lt;p&gt;a 在当前位置后插入&lt;/p&gt;
&lt;p&gt;A 在当前行尾插入&lt;/p&gt;
&lt;p&gt;o 在当前行之后插入一行&lt;/p&gt;
&lt;p&gt;O 在当前行之前插入一行&lt;/p&gt;
&lt;h2 id=&#34;查找命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#查找命令&#34;&gt;#&lt;/a&gt; 查找命令&lt;/h2&gt;
&lt;p&gt;&lt;code&gt; /text　　&lt;/code&gt; 查找 text，按 n 健查找下一个，按 N 健查找前一个。&lt;/p&gt;
&lt;p&gt;&lt;code&gt; ?text　&lt;/code&gt; 　查找 text，反向查找，按 n 健查找下一个，按 N 健查找前一个。&lt;/p&gt;
&lt;p&gt;vim 中有一些特殊字符在查找时需要转义　　.*[]^%/?~$&lt;/p&gt;
&lt;p&gt;&lt;code&gt; :set ignorecase&lt;/code&gt; 　　忽略大小写的查找&lt;/p&gt;
&lt;p&gt;&lt;code&gt; :set noignorecase&lt;/code&gt; 　　不忽略大小写的查找&lt;/p&gt;
&lt;p&gt;查找很长的词，如果一个词很长，键入麻烦，可以将光标移动到该词上，按 * 或 #键即可以该单词进行搜索，相当于 / 搜索。而 #命令相当于？搜索。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:set hlsearch&lt;/code&gt; 　　高亮搜索结果，所有结果都高亮显示，而不是只显示一个匹配。&lt;/p&gt;
&lt;p&gt;&lt;code&gt; :set nohlsearch&lt;/code&gt; 　关闭高亮搜索显示&lt;/p&gt;
&lt;p&gt;&lt;code&gt; :nohlsearch&lt;/code&gt; 　　关闭当前的高亮显示，如果再次搜索或者按下 n 或 N 键，则会再次高亮。&lt;/p&gt;
&lt;p&gt;&lt;code&gt; :set incsearch&lt;/code&gt; 　　逐步搜索模式，对当前键入的字符进行搜索而不必等待键入完成。&lt;/p&gt;
&lt;p&gt;&lt;code&gt; :set wrapscan&lt;/code&gt; 　　重新搜索，在搜索到文件头或尾时，返回继续搜索，默认开启。&lt;/p&gt;
&lt;h2 id=&#34;替换命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#替换命令&#34;&gt;#&lt;/a&gt; 替换命令&lt;/h2&gt;
&lt;p&gt;&lt;code&gt; ra&lt;/code&gt;  将当前字符替换为 a，当期字符即光标所在字符。&lt;/p&gt;
&lt;p&gt;&lt;code&gt; s/old/new/&lt;/code&gt;  用 old 替换 new，替换当前行的第一个匹配&lt;/p&gt;
&lt;p&gt;&lt;code&gt;s/old/new/g&lt;/code&gt;  用 old 替换 new，替换当前行的所有匹配&lt;/p&gt;
&lt;p&gt;&lt;code&gt; %s/old/new/&lt;/code&gt;  用 old 替换 new，替换所有行的第一个匹配&lt;/p&gt;
&lt;p&gt;&lt;code&gt;%s/old/new/g&lt;/code&gt;  用 old 替换 new，替换整个文件的所有匹配&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:10,20 s/^/  /g&lt;/code&gt;  在第 10 行知第 20 行每行前面加四个空格，用于缩进。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ddp&lt;/code&gt;  交换光标所在行和其下紧邻的一行。&lt;/p&gt;
&lt;h2 id=&#34;移动命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#移动命令&#34;&gt;#&lt;/a&gt; 移动命令&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;h&lt;/code&gt;  左移一个字符&lt;br /&gt;
 l 右移一个字符，这个命令很少用，一般用 w 代替。&lt;br /&gt;
 &lt;code&gt;k&lt;/code&gt;  上移一个字符&lt;br /&gt;
 &lt;code&gt;j&lt;/code&gt;  下移一个字符&lt;br /&gt;
以上四个命令可以配合数字使用，比如 20j 就是向下移动 20 行，5h 就是向左移动 5 个字符，在 Vim 中，很多命令都可以配合数字使用，比如删除 10 个字符 10x，在当前位置后插入 3 个！，3a！&amp;lt;Esc&amp;gt;，这里的 Esc 是必须的，否则命令不生效。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;w&lt;/code&gt;  向前移动一个单词（光标停在单词首部），如果已到行尾，则转至下一行行首。此命令快，可以代替 l 命令。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;b&lt;/code&gt;  向后移动一个单词 2b 向后移动 2 个单词&lt;/p&gt;
&lt;p&gt;&lt;code&gt;e&lt;/code&gt; ，同 w，只不过是光标停在单词尾部&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ge&lt;/code&gt; ，同 b，光标停在单词尾部。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;^&lt;/code&gt;  移动到本行第一个非空白字符上。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;0&lt;/code&gt; （数字 0）移动到本行第一个字符上，&lt;/p&gt;
&lt;p&gt;&amp;lt;HOME&amp;gt; 移动到本行第一个字符。同 0 健。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;$ 移动到行尾 3$&lt;/code&gt;  移动到下面 3 行的行尾&lt;/p&gt;
&lt;p&gt;&lt;code&gt;gg&lt;/code&gt;  移动到文件头。 = [[&lt;/p&gt;
&lt;p&gt;&lt;code&gt;G&lt;/code&gt; （shift + g） 移动到文件尾。 = ]]&lt;/p&gt;
&lt;p&gt;&lt;code&gt;f（find）&lt;/code&gt; 命令也可以用于移动，fx 将找到光标后第一个为 x 的字符，3fd 将找到第三个为 d 的字符。&lt;/p&gt;
&lt;p&gt;F 同 f，反向查找。&lt;/p&gt;
&lt;p&gt;跳到指定行，冒号 + 行号，回车，比如跳到 240 行就是 :240 回车。另一个方法是行号 + G，比如 230G 跳到 230 行。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl + e&lt;/code&gt;  向下滚动一行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl + y&lt;/code&gt;  向上滚动一行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl + d&lt;/code&gt;  向下滚动半屏&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl + u&lt;/code&gt;  向上滚动半屏&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl + f&lt;/code&gt;  向下滚动一屏&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl + b&lt;/code&gt;  向上滚动一屏&lt;/p&gt;
&lt;h2 id=&#34;撤销和重做&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#撤销和重做&#34;&gt;#&lt;/a&gt; 撤销和重做&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;u&lt;/code&gt;  撤销（Undo）&lt;br /&gt;
 &lt;code&gt;U&lt;/code&gt;  撤销对整行的操作&lt;br /&gt;
 &lt;code&gt;Ctrl + r&lt;/code&gt;  重做（Redo），即撤销的撤销。&lt;/p&gt;
&lt;h2 id=&#34;删除命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#删除命令&#34;&gt;#&lt;/a&gt; 删除命令&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;x&lt;/code&gt;  删除当前字符&lt;/p&gt;
&lt;p&gt;&lt;code&gt;3x&lt;/code&gt;  删除当前光标开始向后三个字符&lt;/p&gt;
&lt;p&gt;&lt;code&gt;X&lt;/code&gt;  删除当前字符的前一个字符。X=dh&lt;/p&gt;
&lt;p&gt;&lt;code&gt;dl&lt;/code&gt;  删除当前字符， dl=x&lt;/p&gt;
&lt;p&gt;&lt;code&gt;dh&lt;/code&gt;  删除前一个字符&lt;/p&gt;
&lt;p&gt;&lt;code&gt;dd&lt;/code&gt;  删除当前行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;dj&lt;/code&gt;  删除上一行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;dk&lt;/code&gt;  删除下一行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;10d&lt;/code&gt;  删除当前行开始的 10 行。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;D&lt;/code&gt;  删除当前字符至行尾。D=d$&lt;/p&gt;
&lt;p&gt;&lt;code&gt;d&lt;/code&gt; $ 删除当前字符之后的所有字符（本行）&lt;/p&gt;
&lt;p&gt;&lt;code&gt;kdgg&lt;/code&gt;  删除当前行之前所有行（不包括当前行）&lt;/p&gt;
&lt;p&gt;&lt;code&gt;jdG&lt;/code&gt; （jd shift + g）  删除当前行之后所有行（不包括当前行）&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:1,10d&lt;/code&gt;  删除 1-10 行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:11,\$d&lt;/code&gt;  删除 11 行及以后所有的行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:1,\$d&lt;/code&gt;  删除所有行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;J(shift + j)&lt;/code&gt; 　　删除两行之间的空行，实际上是合并两行。&lt;/p&gt;
&lt;h2 id=&#34;拷贝和粘贴&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#拷贝和粘贴&#34;&gt;#&lt;/a&gt; 拷贝和粘贴&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;yy&lt;/code&gt;  拷贝当前行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;nyy&lt;/code&gt;  拷贝当前后开始的 n 行，比如 2yy 拷贝当前行及其下一行。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;p&lt;/code&gt;  在当前光标后粘贴，如果之前使用了 yy 命令来复制一行，那么就在当前行的下一行粘贴。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;shift+p&lt;/code&gt;  在当前行前粘贴&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:1,10 co 20&lt;/code&gt;  将 1-10 行插入到第 20 行之后。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:1,$co$&lt;/code&gt;  将整个文件复制一份并添加到文件尾部。&lt;/p&gt;
&lt;p&gt;正常模式下按 v（逐字）或 V（逐行）进入可视模式，然后用 jklh 命令移动即可选择某些行或字符，再按 y 即可复制&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ddp&lt;/code&gt;  交换当前行和其下一行&lt;/p&gt;
&lt;p&gt;&lt;code&gt;xp&lt;/code&gt;  交换当前字符和其后一个字符&lt;/p&gt;
&lt;h2 id=&#34;剪切命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#剪切命令&#34;&gt;#&lt;/a&gt; 剪切命令&lt;/h2&gt;
&lt;p&gt;正常模式下按 v（逐字）或 V（逐行）进入可视模式，然后用 jklh 命令移动即可选择某些行或字符，再按 d 即可剪切&lt;/p&gt;
&lt;p&gt;ndd 剪切当前行之后的 n 行。利用 p 命令可以对剪切的内容进行粘贴&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:1,10d&lt;/code&gt;  将 1-10 行剪切。利用 p 命令可将剪切后的内容进行粘贴。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:1, 10 m 20&lt;/code&gt;  将第 1-10 行移动到第 20 行之后。&lt;/p&gt;
&lt;h2 id=&#34;退出命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#退出命令&#34;&gt;#&lt;/a&gt; 退出命令&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;:wq&lt;/code&gt;  保存并退出&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ZZ&lt;/code&gt;  保存并退出&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:q!&lt;/code&gt;  强制退出并忽略所有更改&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:e!&lt;/code&gt;  放弃所有修改，并打开原来文件。&lt;/p&gt;
&lt;h2 id=&#34;窗口命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#窗口命令&#34;&gt;#&lt;/a&gt; 窗口命令&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;:split或new&lt;/code&gt;  打开一个新窗口，光标停在顶层的窗口上&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:split file或\:new file&lt;/code&gt;  用新窗口打开文件&lt;/p&gt;
&lt;p&gt;&lt;code&gt;split&lt;/code&gt;  打开的窗口都是横向的，使用 vsplit 可以纵向打开窗口。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl+ww&lt;/code&gt;  移动到下一个窗口&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl+wj&lt;/code&gt;  移动到下方的窗口&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Ctrl+wk&lt;/code&gt;  移动到上方的窗口&lt;/p&gt;
&lt;p&gt;关闭窗口&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:close&lt;/code&gt;  最后一个窗口不能使用此命令，可以防止意外退出 vim。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;:q&lt;/code&gt;  如果是最后一个被关闭的窗口，那么将退出 vim。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;ZZ&lt;/code&gt;  保存并退出。&lt;/p&gt;
&lt;p&gt;关闭所有窗口，只保留当前窗口&lt;/p&gt;
&lt;p&gt;:only&lt;/p&gt;
&lt;p&gt;录制宏&lt;/p&gt;
&lt;p&gt;按 q 键加任意字母开始录制，再按 q 键结束录制（这意味着 vim 中的宏不可嵌套），使用的时候 @加宏名，比如 qa。。。q 录制名为 a 的宏，@a 使用这个宏。&lt;/p&gt;
&lt;h2 id=&#34;执行shell命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#执行shell命令&#34;&gt;#&lt;/a&gt; 执行 shell 命令&lt;/h2&gt;
&lt;p&gt;:!command&lt;/p&gt;
&lt;p&gt;:!ls 列出当前目录下文件&lt;/p&gt;
&lt;p&gt;:!perl -c &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3NjcmlwdC5wbA==&#34;&gt;script.pl&lt;/span&gt; 检查 perl 脚本语法，可以不用退出 vim，非常方便。&lt;/p&gt;
&lt;p&gt;:!perl &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3NjcmlwdC5wbA==&#34;&gt;script.pl&lt;/span&gt; 执行 perl 脚本，可以不用退出 vim，非常方便。&lt;/p&gt;
&lt;p&gt;:suspend 或 Ctrl - Z 挂起 vim，回到 shell，按 fg 可以返回 vim。&lt;/p&gt;
&lt;h2 id=&#34;注释命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#注释命令&#34;&gt;#&lt;/a&gt; 注释命令&lt;/h2&gt;
&lt;p&gt;perl 程序中 #开始的行为注释，所以要注释某些行，只需在行首加入#&lt;/p&gt;
&lt;p&gt;3,5 s/^/#/g 注释第 3-5 行&lt;/p&gt;
&lt;p&gt;3,5 s/^#//g 解除 3-5 行的注释&lt;/p&gt;
&lt;p&gt;1,$ s/^/#/g 注释整个文档。&lt;/p&gt;
&lt;p&gt;:% s/^/#/g 注释整个文档，此法更快。&lt;/p&gt;
&lt;h2 id=&#34;帮助命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#帮助命令&#34;&gt;#&lt;/a&gt; 帮助命令&lt;/h2&gt;
&lt;p&gt;:help or F1 显示整个帮助&lt;br /&gt;
:help xxx 显示 xxx 的帮助，比如 :help i, :help CTRL-[（即 Ctrl+[的帮助）。&lt;br /&gt;
:help &#39;number&#39; Vim 选项的帮助用单引号括起&lt;br /&gt;
:help &amp;lt;Esc&amp;gt; 特殊键的帮助用 &amp;lt;&amp;gt; 扩起&lt;br /&gt;
:help -t Vim 启动参数的帮助用 -&lt;br /&gt;
：help i_&amp;lt;Esc&amp;gt; 插入模式下 Esc 的帮助，某个模式下的帮助用模式_主题的模式&lt;br /&gt;
帮助文件中位于 || 之间的内容是超链接，可以用 Ctrl+] 进入链接，Ctrl+o（Ctrl + t）返回&lt;/p&gt;
&lt;h2 id=&#34;其他非编辑命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#其他非编辑命令&#34;&gt;#&lt;/a&gt; 其他非编辑命令&lt;/h2&gt;
&lt;p&gt;. 重复前一次命令&lt;/p&gt;
&lt;p&gt;:set ruler?　　查看是否设置了 ruler，在.vimrc 中，使用 set 命令设制的选项都可以通过这个命令查看&lt;/p&gt;
&lt;p&gt;:scriptnames　　查看 vim 脚本文件的位置，比如.vimrc 文件，语法文件及 plugin 等。&lt;/p&gt;
&lt;p&gt;:set list 显示非打印字符，如 tab，空格，行尾等。如果 tab 无法显示，请确定用 set lcs=tab:&amp;gt;- 命令设置了.vimrc 文件，并确保你的文件中的确有 tab，如果开启了 expendtab，那么 tab 将被扩展为空格。&lt;/p&gt;
&lt;p&gt;Vim 教程&lt;br /&gt;
在 Unix 系统上&lt;br /&gt;
 $ vimtutor&lt;br /&gt;
 在 Windows 系统上&lt;br /&gt;
:help tutor&lt;/p&gt;
&lt;p&gt;:syntax 列出已经定义的语法项&lt;br /&gt;
:syntax clear 清除已定义的语法规则&lt;br /&gt;
:syntax case match 大小写敏感，int 和 Int 将视为不同的语法元素&lt;br /&gt;
:syntax case ignore 大小写无关，int 和 Int 将视为相同的语法元素，并使用同样的配色方案&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;参考文档：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vc29mdHdhcmV0ZXN0aW5nL2FyY2hpdmUvMjAxMS8wNy8xMi8yMTA0NDM1Lmh0bWw=&#34;&gt;Vim 命令合集&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1 id=&#34;doris-安装部署&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#doris-安装部署&#34;&gt;#&lt;/a&gt; &lt;strong&gt;doris 安装部署&lt;/strong&gt;&lt;/h1&gt;
&lt;h2 id=&#34;一-环境配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一-环境配置&#34;&gt;#&lt;/a&gt; 一、环境配置&lt;/h2&gt;
&lt;h4 id=&#34;1-服务器环境&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-服务器环境&#34;&gt;#&lt;/a&gt; 1. 服务器环境&lt;/h4&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;centos 7&lt;/li&gt;
&lt;li&gt;docker &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb3dubG9hZC5kb2NrZXIuY29tL2xpbnV4L3N0YXRpYy9zdGFibGUveDg2XzY0Lw==&#34;&gt;下载地址&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;doris 1.0.0 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb3Jpcy5hcGFjaGUub3JnL3poLUNOL2Rvd25sb2Fkcy9kb3dubG9hZHMuaHRtbCNkb3Jpcy0lRTQlQjglQkIlRTQlQkIlQTMlRTclQTAlODE=&#34;&gt;下载地址&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;doris &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb3Jpcy5hcGFjaGUub3JnL3poLUNOL2luc3RhbGxpbmcvY29tcGlsYXRpb24uaHRtbA==&#34;&gt;官方文档&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;storrocks &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb2NzLnN0YXJyb2Nrcy5jb20vemgtY24vbWFpbi9xdWlja19zdGFydC9EZXBsb3k=&#34;&gt;官方文档&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3VsdF9tZT90eXBlPWJsb2c=&#34;&gt;学习地址&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;二-安装docker&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#二-安装docker&#34;&gt;#&lt;/a&gt; 二、安装 docker&lt;/h2&gt;
&lt;h3 id=&#34;1-使用xftp-等工具上传docker-安装包到linux服务器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-使用xftp-等工具上传docker-安装包到linux服务器&#34;&gt;#&lt;/a&gt; 1. 使用 xftp 等工具上传 docker 安装包到 linux 服务器&lt;/h3&gt;
&lt;h3 id=&#34;2-解压&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-解压&#34;&gt;#&lt;/a&gt; 2. 解压&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;tar -zxvf docekr-xxx.tgz  
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;3-复制压缩后的文件到指定文件夹&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-复制压缩后的文件到指定文件夹&#34;&gt;#&lt;/a&gt; 3. 复制压缩后的文件到指定文件夹&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;cp docker/* /usr/bin
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;4-注册编辑docker服务&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-注册编辑docker服务&#34;&gt;#&lt;/a&gt; 4. 注册编辑 docker 服务&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;vim /etc/systemd/system/docker.service&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;如果无法使用 vim 可以在 windows 上编辑好文件后上传至 linux 服务器的此目录内&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;参考 docker.service:&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;[Unit]
Description=Docker Application Container Engine
Documentation=https://docs.docker.com
After=network-online.target firewalld.service
Wants=network-online.target

[Service]
LimitNOFILE=1048576
LimitNPROC=1048576
LimitCORE=infinity
Type=notify
# the default is not to use systemd for cgroups because the delegate issues still
# exists and systemd currently does not support the cgroup feature set required
# for containers run by docker
#ExecStart=/usr/bin/dockerd --privileged=true --default-ulimit nofile=65536:65536 -H fd:// 
ExecStart=/usr/bin/dockerd

ExecReload=/bin/kill -s HUP $MAINPID
# Having non-zero Limit*s causes performance problems due to accounting overhead
# in the kernel. We recommend using cgroups to do container-local accounting.
# Uncomment TasksMax if your systemd version supports it.
# Only systemd 226 and above support this version.
#TasksMax=infinity
TimeoutStartSec=0
# set delegate yes so that systemd does not reset the cgroups of docker containers
Delegate=yes
# kill only the docker process, not all processes in the cgroup
KillMode=process
# restart the docker process if it exits prematurely
Restart=on-failure
StartLimitBurst=3
StartLimitInterval=60s

[Install]
WantedBy=multi-user.target 

&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;5-添加可执行权限&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-添加可执行权限&#34;&gt;#&lt;/a&gt; 5. 添加可执行权限&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;chmod +x /etc/systemd/system/docker.service
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;6-一键三连&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6-一键三连&#34;&gt;#&lt;/a&gt; 6. 一键三连&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt; systemctl daemon-reload # 
 systemctl start docker # 启动服务
 systemctl enable docker.service # 设置开机自启动
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;7-docker卸载&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#7-docker卸载&#34;&gt;#&lt;/a&gt; 7. docker 卸载&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;停掉 docker 服务&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;systemctl stop &lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol&gt;
&lt;li&gt;查看 yum 安装的 docker 文件包&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;yum list installed &lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;grep&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol&gt;
&lt;li&gt;删除所有安装的 docker 文件包&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;yum &lt;span class=&#34;token parameter variable&#34;&gt;-y&lt;/span&gt; remove docker.x86_64&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol&gt;
&lt;li&gt;查看 rpm 包是否还有&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;rpm&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-qa&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;grep&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol&gt;
&lt;li&gt;删除 docker 镜像放置的位置&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;rm&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-rf&lt;/span&gt; /var/lib/docker&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;三-安装doris&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三-安装doris&#34;&gt;#&lt;/a&gt; 三、安装 Doris&lt;/h2&gt;
&lt;h3 id=&#34;1-编译&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-编译&#34;&gt;#&lt;/a&gt; 1、编译&lt;/h3&gt;
&lt;h4 id=&#34;1-使用doris源码需要编译这里直接使用物理机编译&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-使用doris源码需要编译这里直接使用物理机编译&#34;&gt;#&lt;/a&gt; 1). 使用【doris】源码，需要编译，这里直接使用物理机编译&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;a).  0.14.0 版本之前版本依赖如下&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;GCC &lt;span class=&#34;token number&#34;&gt;7.3&lt;/span&gt;+, Oracle JDK &lt;span class=&#34;token number&#34;&gt;1.8&lt;/span&gt;+, Python &lt;span class=&#34;token number&#34;&gt;2.7&lt;/span&gt;+, Apache Maven &lt;span class=&#34;token number&#34;&gt;3.5&lt;/span&gt;+, CMake &lt;span class=&#34;token number&#34;&gt;3.11&lt;/span&gt;+ Bison &lt;span class=&#34;token number&#34;&gt;3.0&lt;/span&gt;+&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;如果使用 Ubuntu 16.04 及以上系统 可以执行以下命令来安装依赖&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt-get&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; build-essential openjdk-8-jdk maven cmake byacc flex automake libtool-bin bison binutils-dev libiberty-dev &lt;span class=&#34;token function&#34;&gt;zip&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;unzip&lt;/span&gt; libncurses5-dev &lt;span class=&#34;token function&#34;&gt;curl&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; ninja-build python autopoint pkg-config&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;如果是 CentOS 可以执行以下命令&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; yum groupinstall &lt;span class=&#34;token string&#34;&gt;&#39;Development Tools&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; yum &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; maven cmake byacc flex automake libtool bison binutils-devel &lt;span class=&#34;token function&#34;&gt;zip&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;unzip&lt;/span&gt; ncurses-devel &lt;span class=&#34;token function&#34;&gt;curl&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;wget&lt;/span&gt; python2 glibc-static libstdc++-static java-1.8.0-openjdk&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;b). 在 0.14.0 之后版本依赖如下&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;GCC &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;+, Oracle JDK &lt;span class=&#34;token number&#34;&gt;1.8&lt;/span&gt;+, Python &lt;span class=&#34;token number&#34;&gt;2.7&lt;/span&gt;+, Apache Maven &lt;span class=&#34;token number&#34;&gt;3.5&lt;/span&gt;+, CMake &lt;span class=&#34;token number&#34;&gt;3.19&lt;/span&gt;.2+ Bison &lt;span class=&#34;token number&#34;&gt;3.0&lt;/span&gt;+&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;如果使用 Ubuntu 16.04 及以上系统 可以执行以下命令来安装依赖&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; build-essential openjdk-8-jdk maven cmake byacc flex automake libtool-bin bison binutils-dev libiberty-dev &lt;span class=&#34;token function&#34;&gt;zip&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;unzip&lt;/span&gt; libncurses5-dev &lt;span class=&#34;token function&#34;&gt;curl&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; ninja-build python&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; add-apt-repository ppa:ubuntu-toolchain-r/ppa&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt&lt;/span&gt; update&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; gcc-10 g++-10 &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt-get&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; autoconf automake libtool autopoint&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;如果是 CentOS 可以执行以下命令&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; yum groupinstall &lt;span class=&#34;token string&#34;&gt;&#39;Development Tools&#39;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&amp;amp;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; yum &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; maven cmake byacc flex automake libtool bison binutils-devel &lt;span class=&#34;token function&#34;&gt;zip&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;unzip&lt;/span&gt; ncurses-devel &lt;span class=&#34;token function&#34;&gt;curl&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;wget&lt;/span&gt; python2 glibc-static libstdc++-static java-1.8.0-openjdk&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; yum &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; centos-release-scl&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; yum &lt;span class=&#34;token function&#34;&gt;install&lt;/span&gt; devtoolset-10&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;scl &lt;span class=&#34;token builtin class-name&#34;&gt;enable&lt;/span&gt; devtoolset-10 &lt;span class=&#34;token function&#34;&gt;bash&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;** 安装完成后，自行设置环境变量 PATH, JAVA_HOME 等。(可以通过 alternatives --list 命令找到 jdk 的安装目录) 注意： Doris 0.14.0 的版本仍然使用 gcc7 的依赖编译，之后的代码将使用 gcc10 的依赖 **&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;c). 下载源码&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb3Jpcy5hcGFjaGUub3JnL3poLUNOL2Rvd25sb2Fkcy9kb3dubG9hZHMuaHRtbA==&#34;&gt;官网地址&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;d) 编译&lt;/p&gt;
&lt;p&gt;上传源码到服务器后，解压文件，进入文件夹后，执行编译&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 支持则使用下面命令进行编译&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;$ &lt;span class=&#34;token function&#34;&gt;sh&lt;/span&gt; build.sh&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 如不支持需要加 USE_AVX2=0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;$ &lt;span class=&#34;token assign-left variable&#34;&gt;USE_AVX2&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;sh&lt;/span&gt; build.sh&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;strong&gt;编译完成后，产出文件在 output/ 目录中&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;2-使用starrocks无需编译直接部署即可但cpu需支持avx2指令集&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-使用starrocks无需编译直接部署即可但cpu需支持avx2指令集&#34;&gt;#&lt;/a&gt; 2)、使用【starrocks】无需编译，直接部署即可，但 CPU 需支持【avx2】指令集&lt;/h4&gt;
&lt;blockquote&gt;
&lt;ol&gt;
&lt;li&gt;下载官方镜像 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb2NzLnN0YXJyb2Nrcy5jb20vemgtY24vbWFpbi9hZG1pbmlzdHJhdGlvbi9CdWlsZF9pbl9kb2NrZXI=&#34;&gt;文档&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;2-部署环境准备&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-部署环境准备&#34;&gt;#&lt;/a&gt; 2、部署环境准备&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Linux 操作系统版本需求&lt;/p&gt;
&lt;blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Linux 系统&lt;/th&gt;
&lt;th&gt;版本&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;CentOS&lt;/td&gt;
&lt;td&gt;7.1 及以上&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Ubuntu&lt;/td&gt;
&lt;td&gt;16.04 及以上&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;软件需求&lt;/p&gt;
&lt;blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;软件&lt;/th&gt;
&lt;th&gt;版本&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;java&lt;/td&gt;
&lt;td&gt;1.8+&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;GCC&lt;/td&gt;
&lt;td&gt;4.8.2 及以上&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;操作系统安装要求&lt;br /&gt;
 &lt;code&gt;vi /etc/security/limits.conf&lt;/code&gt; &lt;br /&gt;
# 在末尾加入配置（表示：所有用户所有组，软限制和硬限制，对文件打开数，设为 65535）：&lt;br /&gt;
* soft nofile 65536&lt;br /&gt;
* hard nofile 65536&lt;br /&gt;
# 修改后需要断开远程工具（如 Xshell 等）后重新连接方可生效，或者，直接再临时修改一次，使用：&lt;br /&gt;
​    ulimit -n 65535&lt;br /&gt;
# 确认生效：&lt;br /&gt;
​    ulimit -n&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 检查&lt;/p&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;使用 doris 编译的 可以跳过此检查；&lt;/li&gt;
&lt;li&gt;使用 storrocks 下载部署的，需要检查 cpu 是否支持 &lt;code&gt;avx2&lt;/code&gt;  指令集&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cat&lt;/span&gt; /proc/cpuinfo &lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;grep&lt;/span&gt; avx2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;有结果输出即表明 CPU 支持。如果无输出，则需要更换支持 AVX2 的机器。部分情况下，我们会在 Windows 系统下使用虚拟机安装 CentOS 作为测试环境，此时我们可以使用 CPU-Z、AIDA64 等工具在 Windows 下检查宿主机 CPU 的指令集支持情况。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;操作系统检查&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;StarRocks 要求系统为 Linux CentOS 7 及以上版本（下文演示使用 CentOS 7.6），内核版本建议在 3.10 以上，查看系统及内核信息：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# cat /etc/redhat-release&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; CentOS Linux release &lt;span class=&#34;token number&#34;&gt;7.6&lt;/span&gt;.1810 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Core&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;root@node01 ~&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;# uname -a&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; Linux node01 &lt;span class=&#34;token number&#34;&gt;3.10&lt;/span&gt;.0-1160.25.1.el7.x86_64 &lt;span class=&#34;token comment&#34;&gt;#1 SMP Wed Apr 28 21:49:45 UTC 2021 &gt; x86_64 x86_64 x86_64 GNU/Linux&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;时钟同步&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;Doris 的元数据要求时间精度要小于 5000ms，所以所有集群所有机器要进行时钟同步，避免因为时钟问题引发的元数据不一致导致服务出现异常。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;网络需求&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;Doris、storrocks 各个实例直接通过网络进行通讯。以下表格展示了所有需要的端口&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;实例名&lt;/th&gt;
&lt;th&gt;端口名称&lt;/th&gt;
&lt;th&gt;默认端口&lt;/th&gt;
&lt;th&gt;通信方向&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;BE&lt;/td&gt;
&lt;td&gt;be_port&lt;/td&gt;
&lt;td&gt;9060&lt;/td&gt;
&lt;td&gt;FE--&amp;gt;BE&lt;/td&gt;
&lt;td&gt;BE 上 thrift server 的端口，用于接收来自 FE 的请求&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;BE&lt;/td&gt;
&lt;td&gt;webserver_port&lt;/td&gt;
&lt;td&gt;8040&lt;/td&gt;
&lt;td&gt;BE &amp;lt;--&amp;gt; BE&lt;/td&gt;
&lt;td&gt;BE 上的 http server 的端口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;BE&lt;/td&gt;
&lt;td&gt;heartbeat_service_port&lt;/td&gt;
&lt;td&gt;9050&lt;/td&gt;
&lt;td&gt;FE --&amp;gt; BE&lt;/td&gt;
&lt;td&gt;BE 上心跳服务端口（thrift），用于接收来自 FE 的心跳&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;BE&lt;/td&gt;
&lt;td&gt;brpc_port&lt;/td&gt;
&lt;td&gt;8060&lt;/td&gt;
&lt;td&gt;FE &amp;lt;--&amp;gt; BE, BE &amp;lt;--&amp;gt; BE&lt;/td&gt;
&lt;td&gt;BE 上的 brpc 端口，用于 BE 之间通讯&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FE&lt;/td&gt;
&lt;td&gt;http_port&lt;/td&gt;
&lt;td&gt;8030&lt;/td&gt;
&lt;td&gt;FE &amp;lt;--&amp;gt; FE，用户 &amp;lt;--&amp;gt; FE&lt;/td&gt;
&lt;td&gt;FE 上的 http server 端口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FE&lt;/td&gt;
&lt;td&gt;rpc_port&lt;/td&gt;
&lt;td&gt;9020&lt;/td&gt;
&lt;td&gt;BE --&amp;gt; FE, FE &amp;lt;--&amp;gt; FE&lt;/td&gt;
&lt;td&gt;FE 上的 thrift server 端口，每个 fe 的配置需要保持一致&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FE&lt;/td&gt;
&lt;td&gt;query_port&lt;/td&gt;
&lt;td&gt;9030&lt;/td&gt;
&lt;td&gt;用户 &amp;lt;--&amp;gt; FE&lt;/td&gt;
&lt;td&gt;FE 上的 mysql server 端口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;FE&lt;/td&gt;
&lt;td&gt;edit_log_port&lt;/td&gt;
&lt;td&gt;9010&lt;/td&gt;
&lt;td&gt;FE &amp;lt;--&amp;gt; FE&lt;/td&gt;
&lt;td&gt;FE 上的 bdbje 之间通信用的端口&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Broker&lt;/td&gt;
&lt;td&gt;broker_ipc_port&lt;/td&gt;
&lt;td&gt;8000&lt;/td&gt;
&lt;td&gt;FE --&amp;gt; Broker, BE --&amp;gt; Broker&lt;/td&gt;
&lt;td&gt;Broker 上的 thrift server，用于接收请求&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;strong&gt;注：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;当部署多个 FE 实例时，要保证 FE 的 http_port 配置相同。&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;部署前请确保各个端口在应有方向上的访问权限。&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;若上述端口不与服务器中其他服务的端口冲突，通常不建议修改。&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;以 FE 为例，部署前若需修改端口，可在配置文件 fe/conf/fe.conf 中修改为需要使用的端口（再次注意集群中 FE 的 http 端口需要一致，默认为 8030）：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&amp;lt;!----&amp;gt;&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# store metadata, create it if it is not exist.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# Default value is $&amp;#123;STARROCKS_HOME&amp;#125;/meta&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# meta_dir = $&amp;#123;STARROCKS_HOME&amp;#125;/meta&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;http_port &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;8030&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rpc_port &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;9020&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;query_port &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;9030&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;edit_log_port &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;9010&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;mysql_service_nio_enabled &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;配置防火墙，开放端口&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;防火墙开放集群实例默认端口命令：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;firewall-cmd --zone=public --add-port=8000/tcp --permanent
firewall-cmd --zone=public --add-port=8030/tcp --permanent
firewall-cmd --zone=public --add-port=8040/tcp --permanent
firewall-cmd --zone=public --add-port=8060/tcp --permanent
firewall-cmd --zone=public --add-port=9010/tcp --permanent
firewall-cmd --zone=public --add-port=9020/tcp --permanent
firewall-cmd --zone=public --add-port=9030/tcp --permanent
firewall-cmd --zone=public --add-port=9050/tcp --permanent
firewall-cmd --zone=public --add-port=9060/tcp --permanent
firewall-cmd --reload
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;查看开放的端口：&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code&gt;[root@node01 ~]# firewall-cmd --list-port
8030/tcp 8000/tcp 8060/tcp 9010/tcp 9020/tcp 9030/tcp 9050/tcp 9060/tcp 8040/tcp
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装 JDK&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;StarRocks 依赖 JDK 1.8 + 环境，Oracle JDK 1.8 + 或 OpenJDK8 + 均可以使用（下文演示使用 OpenJDK 1.8.0_41）：&lt;/p&gt;
&lt;p&gt;[root@node01 ~]# java -version&lt;br /&gt;
openjdk version &amp;quot;1.8.0_41&amp;quot;&lt;br /&gt;
OpenJDK Runtime Environment (build 1.8.0_41-b04)&lt;br /&gt;
OpenJDK 64-Bit Server VM (build 25.40-b25, mixed mode)&lt;/p&gt;
&lt;p&gt;OpenJDK 8 的安装操作见：文档：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL25vdGUueW91ZGFvLmNvbS9ub3Rlc2hhcmU/aWQ9NmE5MTA1MmZhZjhkOTJjOGJiNTU5ZDAzMGFmNTAxNzMmYW1wO3N1Yj0wNjY2MEYyQzA0QUM0RDI1OUU3MTJDMzcxODRBRjNCQQ==&#34;&gt;【Linux】安装 OpenJDK.md&lt;/span&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装 Mysql&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;StarRocks 采用 MySQL 协议进行通信，用户可通过 mysql-client 连接到 StarRocks 集群。选 择 mysql-client 版本时要求采用 5.1 之后的版本，因为 5.1 之前不能支持长度超过 16 个字 符的用户名（下文演示使用 mysql -client-5.7.35）。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;为方便集群部署和运维，我们通常建议在集群服务器中选择一个节点安装 mysql-client。当然，我们也可以不安装 mysql-client，通过外部的 SQLyog、DBeaver、Navicat 等图形化工具直接访问 StarRocks。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;mysql 安装操作文档见：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL25vdGUueW91ZGFvLmNvbS9ub3Rlc2hhcmU/aWQ9ZDVhMWZiY2NkNzI3Y2VmZWEzMTdmOWNmMTZmZTVmY2QmYW1wO3N1Yj03Q0E3MjdDQjYzN0Q0NEFFOENFOEM1OUMwMTAxRjMxRQ==&#34;&gt;【Linux】CentOS7 安装 mysql5.7&lt;/span&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-安装部署&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-安装部署&#34;&gt;#&lt;/a&gt; 3、安装部署&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;严格来说，StarRocks 并没有所谓的 “Standalone 运行模式”，生产环境下更是不建议进行单实例部署。这里将单机部署整理出来，主要是考虑当用户测试环境受限于机器数量或仅希望验证功能，那么也可以在一台机器上简易部署把 StarRocks 跑起来。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;以服务器 “starrocks（172.18.88.54）” 为例，在进行完部署环境的准备工作后，我们开始进行单节点的部署。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;单节点架构设计如下：&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;机器节点&lt;/th&gt;
&lt;th&gt;172.18.88.54（starrocks）&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;部署服务&lt;/td&gt;
&lt;td&gt;1 FE(Leader) &amp;lt;/br&amp;gt;1 BE&amp;lt;/br&amp;gt;1 Broker&amp;lt;/br&amp;gt;mysql-client&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;blockquote&gt;
&lt;p&gt;部署目录及数据目录设计如下，后续的部署操作严格按照部署设计进行：&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;服务&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;FE&lt;/td&gt;
&lt;td&gt;部署目录：/opt/module/starrocks/fe &amp;lt;/br&amp;gt; 日志目录：/opt/module/starrocks/fe/log（默认）&amp;lt;/br &amp;gt; 元数据目录：/opt/meta&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;BE&lt;/td&gt;
&lt;td&gt;部署目录：/opt/module/starrocks/be &amp;lt;/br&amp;gt; 日志目录：/opt/module/starrocks/be/log（默认）&amp;lt;/br &amp;gt; 数据目录：/opt/storage&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Broker&lt;/td&gt;
&lt;td&gt;部署目录：/opt/module/starrocks/apache_hdfs_broker&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h4 id=&#34;1-下载二进制包&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-下载二进制包&#34;&gt;#&lt;/a&gt; 1. 下载二进制包&lt;/h4&gt;
&lt;p&gt;StarRocks 的二进制部署包可在官网下载获取：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3RhcnJvY2tzLmNvbS96aC1DTi9kb3dubG9hZC9jb21tdW5pdHk=&#34;&gt;下载地址&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;doris 使用编译到 output 文件中的文件&lt;br /&gt;
这儿是用 storrocks 为例，将下载好的部署包上传至  &lt;code&gt;/opt/software&lt;/code&gt;  目录下&lt;/p&gt;
&lt;blockquote&gt;
&lt;pre&gt;&lt;code&gt;[root@starrocks ~]# mkdir /opt/software
[root@starrocks ~]# cd /opt/software/
[root@starrocks software]# ll
total 988752
-rw-r--r-- 1 root root 1012479814 Nov 22 15:46 StarRocks-1.19.2.tar.gz
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;2-解压-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-解压-2&#34;&gt;#&lt;/a&gt; 2. 解压&lt;/h4&gt;
&lt;blockquote&gt;
&lt;pre&gt;&lt;code&gt;[root@starrocks software]# tar xvf StarRocks-1.19.2.tar.gz
[root@starrocks software]# ll
total 988752
drwxrwxr-x 6 1007 1007        100 Nov 20 20:29 StarRocks-1.19.2
-rw-r--r-- 1 root root 1012479814 Nov 22 15:46 StarRocks-1.19.2.tar.gz
&lt;/code&gt;&lt;/pre&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;starrocks 目录结构：&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;StarRocks-1.19.2
├── apache_hdfs_broker  # Broker目录
│   ├── bin
│   │   ├── start_broker.sh  # Broker启动脚本
│   │   └── stop_broker.sh  # Broker关闭脚本
│   ├── conf
│   │   ├── apache_hdfs_broker.conf  # Broker配置文件
│   │   ├── hdfs-site.xml
│   │   └── log4j.properties
│   └── lib
│       └── *.jar  # Broker依赖的jar包
├── be  # BE实例目录
│   ├── bin
│   │   ├── common.sh
│   │   ├── show_be_version.sh  # BE版本查看
│   │   ├── start_be.sh  # BE启动脚本
│   │   └── stop_be.sh  # BE关闭脚本
│   ├── conf
│   │   ├── be.conf  # BE配置文件
│   │   └── hadoop_env.sh
│   ├── lib
│   │   ├── meta_tool  # Tablet元数据离线管理工具 [1.19版本已合并入starrocks_be]
│   │   └── starrocks_be  # BE可执行文件（小版本升级时替换即可）
│   └── www  # BE Web页面文件
├── fe  # FE实例目录
│   ├── bin
│   │   ├── common.sh
│   │   ├── show_fe_version.sh  # FE版本查看
│   │   ├── start_fe.sh  # FE启动脚本
│   │   └── stop_fe.sh  # FE关闭脚本
│   ├── conf
│   │   ├── fe.conf  # FE配置文件
│   │   └── hadoop_env.sh
│   ├── lib
│   │   ├── starrocks-fe.jar  # FE jar包（小版本升级时替换即可）
│   │   └── *.jar  # FE依赖的jar包
│   ├── log
│   │   └── *.log
│   └── webroot # FE Web页面文件
└── udf # 用户自定义函数目录 [重构中，目前不建议使用]
    ├── include
    │   ├── uda_test_harness.h
    │   └── udf.h  # UDF框架头文件
    └── lib
        └── libStarRocksUdf.a  # UDF框架静态库文件
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;3-分发部署文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-分发部署文件&#34;&gt;#&lt;/a&gt; 3. 分发部署文件&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;# 重命名
[root@starrocks software]# mv /opt/software/StarRocks-1.19.2 /opt/software/starrocks 
# 移动文件到module目录下
[root@starrocks software]# mv /opt/software/starrocks /opt/module/starrocks/
[root@starrocks software]# cd /opt/module/starrocks/
[root@starrocks starrocks]# ll
total 0
drwxr-xr-x. 5 1021 1021 40 Nov 22 14:40 apache_hdfs_broker
